code.perFrame:
zoom = 0.9999;
rot = 0;
dx = 0;
dy = 0;
sx = 0.9999;
sy = 1;
warp = 0.01;
cx = 0.5;
cy = 0.5;
dec_med = 1- .2*30/fps;;
dec_slow = 1-.05*30/fps;;
beat = max (max (bass, mid), treb);;
avg = avg*dec_slow + beat*(1-dec_slow);;
is_beat = ((beat) > (.5*avg+peak)) * ((time) > (t0+.03));;
t0 = is_beat*time + (1-is_beat)*t0;;
peak = is_beat * beat + (1-is_beat)*peak*dec_med;;
index = (index + is_beat) %16;;
index2 = if (bnot(index)*is_beat,index2+1,index2);;
q24 = is_beat;;
q27 = index;;
q28 = index2;;
q22 = peak;;
peak_ = dec_med*peak_ + (1-dec_med)*peak;;
trig = is_beat * bnot(index%4);;
count = count + trig;;
rott = rott*dec_med + (1-dec_med) * count*3.14/2;;
q1 = cos(rott);;
q2 = sin(rott);;
ma = ma + (peak_-0)/fps*4*((peak_) > (0));;
mx=mx*dec_slow+(1-dec_slow)*cos(ma);;
my=my*dec_slow+(1-dec_slow)*sin(ma*q1);;
q15 = mx/2 ;;
q16 = my/2 ;;
q17 = ma;;
ang1 = ang1 + 8*bass*((bass) > (1))/fps*q1;;
q18 = ang1;;
q32 = aspecty;;
monitor = index2;
